using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tipo de movimento de um inimigo (Enemy Creator — Etapa 1.5).
///
/// - Estatico: nunca se move (Torretas/Armadilhas). EnemyMovement não faz
///   nada em FixedUpdate; o inimigo pode ainda detectar (1.4) e atacar (2.1)
///   sem se deslocar.
/// - Terrestre: anda no chão. Respeita gravidade, paredes ("wallCheckDistance")
///   e bordas de plataforma ("respectLedges" — se desligado, pode cair de
///   plataformas).
/// - Flutuante/Voador/Nadador/Mergulhador: movimento livre em X e Y, sem
///   gravidade (gravityScale = 0) nem dependência do chão — ex: um Voador que
///   persegue o player sobe/desce livremente. As configurações específicas de
///   água (correntes, flutuabilidade) são adicionadas na Etapa 3 por cima
///   deste movimento base.
/// </summary>
public enum EnemyMovementType
{
    Estatico,
    Terrestre,
    Flutuante,
    Voador,
    Nadador,
    Mergulhador
}

/// <summary>
/// Comportamento deste inimigo em relação ao alvo durante o estado
/// Perseguindo (e ao calcular a velocidade alvo em VoltandoParaCasa).
/// </summary>
public enum EnemyChaseBehavior
{
    /// <summary>Aproxima-se do alvo até "stopDistance".</summary>
    Perseguir,

    /// <summary>Mantém-se a cerca de "keepDistance" do alvo (ex: atiradores/voadores que disparam de longe).</summary>
    ManterDistancia,

    /// <summary>Afasta-se do alvo (ex: presas/civis assustados).</summary>
    Fugir
}

/// <summary>
/// Estilo do movimento livre (Voador/Flutuante/Nadador/Mergulhador — Etapa 3.4).
/// </summary>
public enum FreeMoveStyle
{
    /// <summary>Velocidade definida directamente — vira instantaneamente (comportamento original).</summary>
    Continuo,

    /// <summary>Acelera/trava gradualmente — desliza um pouco antes de virar para o outro lado (voadores com inércia, peixes que deslizam).</summary>
    Inercia,

    /// <summary>Impulsos periódicos tipo lula/medusa: acelera num jato e desacelera até ao próximo impulso.</summary>
    Impulso
}

/// <summary>Eixos permitidos no movimento livre (Etapa 3.4).</summary>
public enum FreeMoveAxes
{
    /// <summary>8 direcções livres (qualquer ângulo).</summary>
    OitoDirecoes,

    /// <summary>Uma direcção de cada vez: só cima/baixo OU esquerda/direita (eixo dominante).</summary>
    UmEixoDeCadaVez
}

/// <summary>Estilo de perseguição (Etapa 3.4).</summary>
public enum ChasePursuitStyle
{
    /// <summary>Persegue continuamente (comportamento original).</summary>
    Continua,

    /// <summary>Pára, olha para o herói, e corre até ele em arrancadas — re-apontando se o herói desviar. Saltos/dashes/tiros durante a perseguição vêm da lista de ataques (Attack_JumpAtPlayer com 'jumpHeight', Attack_HorizontalDash, projécteis).</summary>
    PararOlharCorrer
}

/// <summary>
/// Movimento e patrulha de um inimigo (Enemy Creator — Etapa 1.5), baseado no
/// padrão de NpcMovement (NPC/NpcMovement.cs): pontos de patrulha como
/// deslocamentos relativos a uma posição base, viragem em paredes/bordas via
/// raycasts, e viragem do sprite (flipX) consoante a direcção do movimento.
///
/// Em vez de "_startPosition" (NpcMovement), a base da patrulha é
/// <see cref="EnemyController.HomePosition"/>. Se "patrolPoints" estiver
/// vazio, gera automaticamente uma pequena área de patrulha ao redor do
/// inimigo (ver "defaultPatrolSize").
///
/// Reage ao <see cref="EnemyController.State"/> (definido por EnemyDetection —
/// Etapa 1.4 — e EnemyHealth/EnemyAttack nas etapas seguintes):
///
/// - Patrulhando: segue "patrolPoints".
/// - Perseguindo: aproxima-se/mantém distância/afasta-se de
///   <see cref="EnemyController.Target"/> conforme "chaseBehavior".
/// - VoltandoParaCasa: volta para "HomePosition" e, ao chegar, volta a
///   transitar para Patrulhando.
/// - Qualquer outro estado (Idle, Alerta, PreparandoAtaque, Atacando,
///   Recuperando, Atordoado, Desactivado, Morto): pára o movimento horizontal
///   (ou todo, em movimento livre) — esses estados são geridos por outros
///   componentes (EnemyDetection, EnemyAttack, EnemyHealth).
/// </summary>
[RequireComponent(typeof(EnemyController))]
public class EnemyMovement : MonoBehaviour
{
    [Header("Tipo de Movimento")]
    public EnemyMovementType movementType = EnemyMovementType.Terrestre;

    [Header("Patrulha")]
    [Tooltip("Pontos de patrulha como deslocamento relativo a EnemyController.HomePosition. Vazio = gera automaticamente uma pequena área (ver 'Tamanho da Patrulha por Defeito').")]
    public List<Vector2> patrolPoints = new List<Vector2>();

    public PatrolLoopMode patrolLoopMode = PatrolLoopMode.PingPong;

    [Tooltip("Tamanho (metros) da área de patrulha gerada automaticamente quando 'Patrol Points' está vazio. Gera 2 pontos, a +/- metade deste valor de HomePosition.")]
    public float defaultPatrolSize = 2f;

    [Tooltip("Tempo (segundos) parado em cada ponto de patrulha antes de seguir para o próximo.")]
    public float patrolWaitTime = 1f;

    [Tooltip("Velocidade durante a patrulha (Estado Patrulhando).")]
    public float patrolSpeed = 1.5f;

    [Tooltip("Distância ao ponto/alvo considerada 'chegou'.")]
    public float stopDistance = 0.1f;

    [Header("Perseguição")]
    public EnemyChaseBehavior chaseBehavior = EnemyChaseBehavior.Perseguir;

    [Tooltip("Velocidade ao perseguir/fugir/manter distância (Perseguindo) e ao voltar para casa (VoltandoParaCasa). Se <= 0, usa EnemyData.stats.moveSpeed.")]
    public float chaseSpeed = 0f;

    [Tooltip("Distância ideal mantida do alvo (ManterDistancia).")]
    public float keepDistance = 4f;

    [Tooltip("Margem de tolerância em torno de 'keepDistance' antes de se mover para aproximar/afastar.")]
    public float keepDistanceTolerance = 0.5f;

    [Header("Estilo de Perseguição (Etapa 3.4)")]
    [Tooltip("Continua = persegue sempre. PararOlharCorrer = pára a olhar para o herói durante 'lookPauseDuration' e depois corre até ele durante 'runBurstDuration' (re-apontando se ele desviar).")]
    public ChasePursuitStyle pursuitStyle = ChasePursuitStyle.Continua;

    [Tooltip("Tempo parado a olhar para o herói antes de cada arrancada (PararOlharCorrer).")]
    public float lookPauseDuration = 0.8f;

    [Tooltip("Duração de cada arrancada em direcção ao herói (PararOlharCorrer).")]
    public float runBurstDuration = 1.2f;

    [Header("Estilo de Movimento Livre (Voador/Flutuante/Nadador/Mergulhador — Etapa 3.4)")]
    [Tooltip("Continuo = vira instantaneamente. Inercia = desliza antes de virar. Impulso = jatos periódicos tipo lula.")]
    public FreeMoveStyle freeMoveStyle = FreeMoveStyle.Continuo;

    [Tooltip("8 direcções livres, ou uma direcção de cada vez (cima/baixo OU esquerda/direita).")]
    public FreeMoveAxes freeMoveAxes = FreeMoveAxes.OitoDirecoes;

    [Tooltip("Aceleração (m/s²) do estilo Inercia — mais baixo = desliza mais antes de virar.")]
    public float inertiaAcceleration = 8f;

    [Tooltip("Intervalo (s) entre impulsos do estilo Impulso (lula).")]
    public float impulseInterval = 0.9f;

    [Tooltip("Desaceleração (m/s²) entre impulsos do estilo Impulso.")]
    public float impulseDamping = 3f;

    [Header("Terreno Escorregadio (Terrestre — Etapa 3.4)")]
    [Tooltip("Se activo, em cima de terreno das camadas 'slipperyGroundMask' o inimigo acelera/trava gradualmente (desliza) em vez de mudar de velocidade instantaneamente.")]
    public bool affectedBySlipperyGround = true;

    [Tooltip("Camadas de terreno escorregadio (gelo, lama, etc). Vazio = nunca desliza.")]
    public LayerMask slipperyGroundMask;

    [Tooltip("Aceleração horizontal (m/s²) em terreno escorregadio — mais baixo = desliza mais.")]
    public float slipperyAcceleration = 4f;

    [Header("Voltar para Casa")]
    [Tooltip("Distância a HomePosition considerada 'chegou' (volta a Patrulhando).")]
    public float returnArriveDistance = 0.2f;

    [Header("Paredes / Bordas (Terrestre)")]
    [Tooltip("Camadas consideradas 'chão/paredes'. Vazio = sem verificação (ignora paredes e bordas).")]
    public LayerMask groundMask;

    [Tooltip("Se activo, o inimigo não anda para fora de uma plataforma. Se desligado, pode cair de plataformas.")]
    public bool respectLedges = true;

    public float wallCheckDistance = 0.3f;
    public float groundCheckDistance = 0.6f;

    [Tooltip("Deslocamento do ponto de onde parte o raio de detecção de chão (o X é espelhado consoante a direcção do movimento).")]
    public Vector2 groundCheckOffset = new Vector2(0.4f, 0f);

    [Header("Visual")]
    [Tooltip("Auto-detectado se vazio.")]
    [SerializeField] private SpriteRenderer spriteRenderer;

    public bool faceMovementDirection = true;
    public bool spriteFacesRightByDefault = true;

    private EnemyController _controller;
    private Rigidbody2D _rb;

    private int _patrolIndex;
    private int _patrolDir = 1;
    private float _patrolWaitTimer;
    private float _resolvedChaseSpeed;

    // Estilo de perseguição PararOlharCorrer (Etapa 3.4).
    private bool _pursuitRunning;
    private float _pursuitTimer;

    // Estilo de movimento livre Impulso (Etapa 3.4).
    private float _impulseTimer;

    /// <summary>Tipos de movimento livre em X/Y (sem gravidade nem dependência do chão).</summary>
    private bool IsFreeMovement => IsFreeMovementType(movementType);

    /// <summary>
    /// Devolve true se "type" é um tipo de movimento livre em X/Y (sem
    /// gravidade nem dependência do chão): Flutuante, Voador, Nadador ou
    /// Mergulhador. Estático e Terrestre devolvem false. Usado também por
    /// EnemyControllerEditor (Etapa 1.6) para decidir se os handles de
    /// patrulha podem ser arrastados livremente em Y.
    /// </summary>
    public static bool IsFreeMovementType(EnemyMovementType type)
    {
        return type == EnemyMovementType.Voador ||
               type == EnemyMovementType.Flutuante ||
               type == EnemyMovementType.Nadador ||
               type == EnemyMovementType.Mergulhador;
    }

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _rb = _controller.Rb;

        if (spriteRenderer == null)
            spriteRenderer = _controller.SpriteRenderer;

        if (_rb != null && IsFreeMovement)
            _rb.gravityScale = 0f;
    }

    private void Start()
    {
        if (movementType == EnemyMovementType.Estatico) return;

        if (patrolPoints == null || patrolPoints.Count == 0)
            patrolPoints = BuildDefaultPatrolPoints();

        var stats = _controller.Data != null ? _controller.Data.stats : null;
        _resolvedChaseSpeed = chaseSpeed > 0f
            ? chaseSpeed
            : (stats != null && stats.moveSpeed > 0f ? stats.moveSpeed : 2f);

        if (_controller.State == EnemyState.Idle)
            _controller.SetState(EnemyState.Patrulhando);
    }

    private void FixedUpdate()
    {
        if (movementType == EnemyMovementType.Estatico) return;
        if (_rb == null) return;

        if (_controller.IsTerminal)
        {
            StopMovement();
            return;
        }

        // Fora de Perseguindo, o ciclo "parar-olhar-correr" recomeça na fase "olhar".
        if (_controller.State != EnemyState.Perseguindo)
        {
            _pursuitRunning = false;
            _pursuitTimer = lookPauseDuration;
        }

        switch (_controller.State)
        {
            case EnemyState.Patrulhando:
                ApplyPatrol();
                break;

            case EnemyState.Perseguindo:
                ApplyChase();
                break;

            case EnemyState.VoltandoParaCasa:
                ApplyReturnHome();
                break;

            case EnemyState.Atacando:
                // O EnemyAttack em execução (Etapa 2.1) controla o Rigidbody2D
                // durante a fase activa (ex: investida, salto, ataque
                // cima-para-baixo). EnemyMovement não interfere.
                break;

            default:
                // Idle/Alerta/PreparandoAtaque/Recuperando/Atordoado:
                // geridos por EnemyDetection/EnemyAttack/EnemyHealth.
                StopMovement();
                break;
        }
    }

    private void ApplyPatrol()
    {
        if (patrolPoints == null || patrolPoints.Count == 0)
        {
            StopMovement();
            return;
        }

        if (_patrolWaitTimer > 0f)
        {
            _patrolWaitTimer -= Time.fixedDeltaTime;
            StopMovement();
            return;
        }

        Vector2 targetPos = (Vector2)_controller.HomePosition + patrolPoints[_patrolIndex];
        Vector2 toTarget = targetPos - (Vector2)transform.position;
        float dist = IsFreeMovement ? toTarget.magnitude : Mathf.Abs(toTarget.x);

        if (dist <= stopDistance)
        {
            _patrolWaitTimer = patrolWaitTime;
            AdvancePatrolIndex();
            StopMovement();
            return;
        }

        Vector2 dir = IsFreeMovement ? toTarget.normalized : new Vector2(Mathf.Sign(toTarget.x), 0f);

        if (!IsFreeMovement && !CanMove(dir.x))
        {
            // Obstáculo ou borda à frente: espera e avança para o próximo ponto.
            _patrolWaitTimer = patrolWaitTime;
            AdvancePatrolIndex();
            StopMovement();
            return;
        }

        Move(dir, patrolSpeed);
    }

    private void AdvancePatrolIndex()
    {
        if (patrolPoints.Count <= 1) return;

        if (patrolLoopMode == PatrolLoopMode.Loop)
        {
            _patrolIndex = (_patrolIndex + 1) % patrolPoints.Count;
            return;
        }

        if (_patrolIndex + _patrolDir < 0 || _patrolIndex + _patrolDir >= patrolPoints.Count)
            _patrolDir = -_patrolDir;

        _patrolIndex += _patrolDir;
    }

    private void ApplyChase()
    {
        var target = _controller.Target;
        if (target == null)
        {
            StopMovement();
            return;
        }

        Vector2 toTarget = (Vector2)target.position - (Vector2)transform.position;
        float dist = toTarget.magnitude;

        // Estilo "param, olham pro herói, correm até ele" (Etapa 3.4): durante a
        // fase de pausa fica parado a encarar o alvo; na fase de arrancada cai
        // no código normal abaixo (que já re-aponta a direcção a cada frame —
        // se o herói desviar, o inimigo desvia também).
        if (pursuitStyle == ChasePursuitStyle.PararOlharCorrer)
        {
            _pursuitTimer -= Time.fixedDeltaTime;

            if (!_pursuitRunning)
            {
                StopMovement();
                FaceDirection(toTarget.x);

                if (_pursuitTimer <= 0f)
                {
                    _pursuitRunning = true;
                    _pursuitTimer = runBurstDuration;
                }

                return;
            }

            if (_pursuitTimer <= 0f)
            {
                _pursuitRunning = false;
                _pursuitTimer = lookPauseDuration;
            }
        }

        Vector2 desiredDir;
        switch (chaseBehavior)
        {
            case EnemyChaseBehavior.Fugir:
                desiredDir = dist > 0.01f ? -toTarget.normalized : Vector2.zero;
                break;

            case EnemyChaseBehavior.ManterDistancia:
                if (dist < keepDistance - keepDistanceTolerance)
                    desiredDir = dist > 0.01f ? -toTarget.normalized : Vector2.zero;
                else if (dist > keepDistance + keepDistanceTolerance)
                    desiredDir = toTarget.normalized;
                else
                    desiredDir = Vector2.zero;
                break;

            default: // Perseguir
                desiredDir = dist > stopDistance ? toTarget.normalized : Vector2.zero;
                break;
        }

        if (desiredDir == Vector2.zero)
        {
            StopMovement();
            FaceDirection(toTarget.x);
            return;
        }

        if (!IsFreeMovement && !CanMove(Mathf.Sign(desiredDir.x)))
        {
            StopMovement();
            FaceDirection(toTarget.x);
            return;
        }

        Move(desiredDir, _resolvedChaseSpeed);
    }

    private void ApplyReturnHome()
    {
        Vector2 home = _controller.HomePosition;
        Vector2 toHome = home - (Vector2)transform.position;
        float dist = IsFreeMovement ? toHome.magnitude : Mathf.Abs(toHome.x);

        if (dist <= returnArriveDistance)
        {
            StopMovement();
            _controller.SetState(EnemyState.Patrulhando);
            return;
        }

        Vector2 dir = IsFreeMovement ? toHome.normalized : new Vector2(Mathf.Sign(toHome.x), 0f);

        if (!IsFreeMovement && !CanMove(dir.x))
        {
            // Não consegue voltar pelo caminho directo: fica à espera em Patrulhando.
            StopMovement();
            _controller.SetState(EnemyState.Patrulhando);
            return;
        }

        Move(dir, _resolvedChaseSpeed);
    }

    /// <summary>Aplica velocidade na direcção "dir" (normalizada para movimento livre; só o sinal de X importa para movimento terrestre).</summary>
    private void Move(Vector2 dir, float speed)
    {
        if (IsFreeMovement)
        {
            MoveFree(dir, speed);
            return;
        }

        if (Mathf.Approximately(dir.x, 0f))
        {
            StopMovement();
            return;
        }

        float dirX = Mathf.Sign(dir.x);

        // Terreno escorregadio (Etapa 3.4): acelera gradualmente em vez de
        // definir a velocidade directamente — o inimigo desliza.
        if (IsOnSlipperyGround())
        {
            float newX = Mathf.MoveTowards(_rb.velocity.x, dirX * speed, slipperyAcceleration * Time.fixedDeltaTime);
            _rb.velocity = new Vector2(newX, _rb.velocity.y);
        }
        else
        {
            _rb.velocity = new Vector2(dirX * speed, _rb.velocity.y);
        }

        FaceDirection(dirX);
    }

    /// <summary>Movimento livre em X/Y com estilo (Etapa 3.4): Continuo, Inercia (desliza ao virar) ou Impulso (jatos tipo lula); eixos livres ou um de cada vez.</summary>
    private void MoveFree(Vector2 dir, float speed)
    {
        if (dir.sqrMagnitude < 0.0001f)
        {
            StopMovement();
            return;
        }

        dir = dir.normalized;

        // Uma direcção de cada vez: usa só o eixo dominante (cima/baixo OU esquerda/direita).
        if (freeMoveAxes == FreeMoveAxes.UmEixoDeCadaVez)
        {
            dir = Mathf.Abs(dir.x) >= Mathf.Abs(dir.y)
                ? new Vector2(Mathf.Sign(dir.x), 0f)
                : new Vector2(0f, Mathf.Sign(dir.y));
        }

        switch (freeMoveStyle)
        {
            case FreeMoveStyle.Inercia:
                _rb.velocity = Vector2.MoveTowards(_rb.velocity, dir * speed, inertiaAcceleration * Time.fixedDeltaTime);
                break;

            case FreeMoveStyle.Impulso:
                _impulseTimer -= Time.fixedDeltaTime;

                if (_impulseTimer <= 0f)
                {
                    _rb.velocity = dir * speed; // jato
                    _impulseTimer = Mathf.Max(0.05f, impulseInterval);
                }
                else
                {
                    // entre impulsos, desacelera (deslize da lula)
                    _rb.velocity = Vector2.MoveTowards(_rb.velocity, Vector2.zero, impulseDamping * Time.fixedDeltaTime);
                }
                break;

            default: // Continuo
                _rb.velocity = dir * speed;
                break;
        }

        FaceDirection(dir.x);
    }

    private void StopMovement()
    {
        if (_rb == null) return;

        if (IsFreeMovement)
        {
            // Estilos com deslize param gradualmente (não estacam no ar/água).
            if (freeMoveStyle == FreeMoveStyle.Inercia)
                _rb.velocity = Vector2.MoveTowards(_rb.velocity, Vector2.zero, inertiaAcceleration * Time.fixedDeltaTime);
            else if (freeMoveStyle == FreeMoveStyle.Impulso)
                _rb.velocity = Vector2.MoveTowards(_rb.velocity, Vector2.zero, impulseDamping * Time.fixedDeltaTime);
            else
                _rb.velocity = Vector2.zero;

            return;
        }

        // Terrestre: em terreno escorregadio trava gradualmente (desliza até parar).
        if (IsOnSlipperyGround())
        {
            float newX = Mathf.MoveTowards(_rb.velocity.x, 0f, slipperyAcceleration * Time.fixedDeltaTime);
            _rb.velocity = new Vector2(newX, _rb.velocity.y);
            return;
        }

        _rb.velocity = new Vector2(0f, _rb.velocity.y);
    }

    /// <summary>True se o inimigo terrestre está em cima de terreno escorregadio (raycast para baixo contra "slipperyGroundMask" — Etapa 3.4).</summary>
    private bool IsOnSlipperyGround()
    {
        if (!affectedBySlipperyGround || slipperyGroundMask.value == 0) return false;

        float dist = groundCheckDistance > 0f ? groundCheckDistance : 0.6f;
        return Physics2D.Raycast(transform.position, Vector2.down, dist, slipperyGroundMask).collider != null;
    }

    /// <summary>Verifica parede ("wallCheckDistance") e borda ("groundCheckDistance", se "respectLedges") na direcção "dir". Ignorado em movimento livre.</summary>
    private bool CanMove(float dir)
    {
        if (groundMask.value == 0) return true;
        if (Mathf.Approximately(dir, 0f)) return true;

        if (wallCheckDistance > 0f)
        {
            var wallHit = Physics2D.Raycast(transform.position, new Vector2(dir, 0f), wallCheckDistance, groundMask);
            if (wallHit.collider != null) return false;
        }

        if (respectLedges && groundCheckDistance > 0f)
        {
            Vector2 origin = (Vector2)transform.position + new Vector2(groundCheckOffset.x * Mathf.Sign(dir), groundCheckOffset.y);
            var groundHit = Physics2D.Raycast(origin, Vector2.down, groundCheckDistance, groundMask);
            if (groundHit.collider == null) return false;
        }

        return true;
    }

    /// <summary>Vira o sprite (flipX) para olhar na direcção "dirX" (positivo = direita, negativo = esquerda). Não faz nada se dirX for ~0.</summary>
    public void FaceDirection(float dirX)
    {
        if (!faceMovementDirection || spriteRenderer == null || Mathf.Approximately(dirX, 0f)) return;

        bool facingRight = dirX > 0f;
        spriteRenderer.flipX = spriteFacesRightByDefault ? !facingRight : facingRight;
    }

    private List<Vector2> BuildDefaultPatrolPoints()
    {
        float half = Mathf.Max(0.1f, defaultPatrolSize) * 0.5f;
        return new List<Vector2> { new Vector2(-half, 0f), new Vector2(half, 0f) };
    }

    private void OnDrawGizmosSelected()
    {
        if (movementType == EnemyMovementType.Estatico) return;

        var points = (patrolPoints != null && patrolPoints.Count > 0) ? patrolPoints : BuildDefaultPatrolPoints();
        if (points.Count == 0) return;

        Vector2 basePos = transform.position;
        if (Application.isPlaying)
        {
            var ctrl = _controller != null ? _controller : GetComponent<EnemyController>();
            if (ctrl != null) basePos = ctrl.HomePosition;
        }

        Gizmos.color = Color.yellow;

        Vector2 prev = basePos + points[0];
        Gizmos.DrawWireSphere(prev, 0.2f);

        for (int i = 1; i < points.Count; i++)
        {
            Vector2 point = basePos + points[i];
            Gizmos.DrawLine(prev, point);
            Gizmos.DrawWireSphere(point, 0.2f);
            prev = point;
        }

        if (patrolLoopMode == PatrolLoopMode.Loop && points.Count > 1)
            Gizmos.DrawLine(prev, basePos + points[0]);

        if (chaseBehavior == EnemyChaseBehavior.ManterDistancia)
        {
            Gizmos.color = new Color(0f, 1f, 1f, 0.4f);
            Gizmos.DrawWireSphere(transform.position, keepDistance);
        }
    }
}
